{
  "summary": "This paper proposes CORA, a unified model for multilingual open question answering that jointly performs cross-lingual dense passage retrieval and answer generation without relying on external translation or language-specific modules. Through iterative training with cross-lingual data expansion leveraging Wikipedia language links and Wikidata, CORA achieves state-of-the-art results on two multilingual QA benchmarks, including strong zero-shot performance on unseen languages.",
  "strengths": [
    {
      "point": "Unified cross-lingual retrieval and generation framework",
      "evidence": "CORA integrates a multilingual dense passage retriever (mDPR) and a multilingual answer generator (mGEN) into a single model that retrieves and generates answers across languages without external translation."
    },
    {
      "point": "Iterative training with cross-lingual data expansion",
      "evidence": "The method leverages Wikipedia language links and Wikidata to mine additional training data in multiple languages, improving performance without requiring additional human annotation or machine translation."
    },
    {
      "point": "Strong empirical performance on diverse multilingual benchmarks",
      "evidence": "CORA outperforms prior state-of-the-art by large margins on XOR-TYDI QA (+21.4 F1) and MKQA (+4.9 F1), including 9 unseen languages where it achieves ~30 F1, surpassing previous methods by 5.4 F1."
    },
    {
      "point": "Comprehensive analysis of cross-lingual retrieval benefits",
      "evidence": "The paper provides ablations and human evaluations showing that retrieval from multiple languages, especially typologically similar ones, significantly improves QA performance for low-resource and unseen languages."
    }
  ],
  "weaknesses": [
    {
      "point": "Insufficient comparison to prior multilingual dense retrieval models",
      "evidence": "The paper lacks detailed architectural or training comparisons to existing multilingual dense retrievers such as mDPR variants, weakening the novelty claim."
    },
    {
      "point": "Limited analysis of iterative training design choices and robustness",
      "evidence": "No ablation or sensitivity analysis on number of iterations, convergence criteria, or hyperparameter impact in the iterative training process is provided."
    },
    {
      "point": "Dependence on Wikipedia language links and Wikidata limits generalizability",
      "evidence": "The approach relies heavily on these structured resources, which may not cover truly low-resource or domain-specific languages, and this limitation is not discussed."
    },
    {
      "point": "Evaluation metrics and human evaluation are limited",
      "evidence": "Only F1 scores are reported without Exact Match or retrieval recall; human evaluation assesses only passage relevance, not answer correctness or fluency."
    },
    {
      "point": "Reproducibility details are insufficient",
      "evidence": "Training hyperparameters, hardware, training time, passage indexing, and retrieval efficiency details are missing, hindering reproducibility."
    },
    {
      "point": "Clarity issues in some methodological aspects",
      "evidence": "The paper does not clearly explain how mGEN conditions on multilingual passages, how new passages are labeled automatically, or how tokenization/script differences are handled."
    },
    {
      "point": "Limited discussion of limitations and error analysis",
      "evidence": "No treatment of ambiguous or multi-hop questions; error analysis focuses mainly on retrieval errors without deep analysis of generation errors or mitigation strategies."
    },
    {
      "point": "Domain generalizability not explored",
      "evidence": "Experiments and training are restricted to Wikipedia passages; applicability to other domains or noisy real-world data is not investigated."
    }
  ],
  "questions": [
    {
      "question": "How does CORA compare architecturally and in training methodology to existing multilingual dense retrieval models?",
      "motivation": "Clarifying this would strengthen the novelty claim and contextualize the contribution relative to prior work."
    },
    {
      "question": "How sensitive is the iterative training process to hyperparameters and number of iterations, and what are the convergence criteria?",
      "motivation": "Understanding robustness is important for reproducibility and practical adoption."
    },
    {
      "question": "How does CORA handle languages with different scripts or tokenization challenges, especially low-resource or morphologically rich languages?",
      "motivation": "This affects the model’s true multilingual and cross-script applicability."
    },
    {
      "question": "Can the approach be extended or adapted to domains beyond Wikipedia, and how would performance be affected?",
      "motivation": "Demonstrating domain generalizability is important for broader real-world impact."
    },
    {
      "question": "What are the criteria or thresholds used to label new passages as positive or negative during data expansion?",
      "motivation": "This impacts training quality and stability, and clarity would aid reproducibility."
    }
  ],
  "scores": {
    "correctness": 3,
    "novelty": 3,
    "recommendation": "borderline",
    "confidence": 3
  }
}
